import{c as a,Q as o,j as d,m as c}from"./chunks/framework.BPKcPtvA.js";const h=JSON.parse('{"title":"GPT接入CC","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/ChatGPTClaudeCode.md","filePath":"advanced/ChatGPTClaudeCode.md","lastUpdated":1779875172000}'),t={name:"advanced/ChatGPTClaudeCode.md"};function i(l,e,s,p,C,r){return o(),d("div",null,[...e[0]||(e[0]=[c('<h1 id="gpt接入cc" tabindex="-1">GPT接入CC <a class="header-anchor" href="#gpt接入cc" aria-label="Permalink to &quot;GPT接入CC&quot;">​</a></h1><hr><p>重要告警</p><p>我们不推荐将 GPT 模型接入 Claude Code。更稳妥的使用方式是：GPT 模型在 Codex 中使用，Claude 模型在 Claude Code 中使用。</p><p>本教程仅用于回应部分用户的测试需求。该方案依赖 <code>codex</code> 分组与 CC Switch 本地路由，可能出现缓存异常、模型映射异常、MCP 或 Skills 兼容性问题。由此产生的任何使用问题、额度消耗、配置异常或其他后果，Suirenai 不推荐、不承诺可用性，也不承担责任。</p><p>请仅在你清楚风险，并具备自行排查问题能力时尝试；新手用户不建议操作。</p><h2 id="前置准备" tabindex="-1">前置准备 <a class="header-anchor" href="#前置准备" aria-label="Permalink to &quot;前置准备&quot;">​</a></h2><p>本教程用于将 <strong>codex</strong> 分组中的 GPT 模型接入 <strong>Claude Code</strong> 使用。开始前请先确认本地已经完成 Claude Code 安装；如果还没有安装，可以先参考 <a href="/cli/2-claude.html">Claude Code配置</a> 中的安装与基础配置步骤。</p><p>同时，请确认本地已经安装并打开 CC Switch。该方案必须依赖 CC Switch 的本地路由能力，不能只通过普通供应商配置完成。</p><h2 id="创建-codex-令牌" tabindex="-1">创建 codex 令牌 <a class="header-anchor" href="#创建-codex-令牌" aria-label="Permalink to &quot;创建 codex 令牌&quot;">​</a></h2><ol><li><p>回顾 <a href="/register/4-token.html">创建 API 令牌</a>，在 Suirenai 中创建新的 API 令牌。</p></li><li><p>名称可以填写 <code>codex</code>，密钥分组请选择 <code>codex</code>。创建完成后，复制生成的 API Key，后续配置会用到。</p></li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ChatGPTClaudeCode/01.webp" alt=""></p><h2 id="使用-cc-switch-配置" tabindex="-1">使用 CC Switch 配置 <a class="header-anchor" href="#使用-cc-switch-配置" aria-label="Permalink to &quot;使用 CC Switch 配置&quot;">​</a></h2><p>使用前确认</p><p>此配置不是 Claude Code 的常规推荐配置。配置完成后，请以 Claude Code 实际对话结果、CC Switch 请求日志和 Suirenai 消费日志共同判断是否生效。</p><h3 id="添加供应商" tabindex="-1">添加供应商 <a class="header-anchor" href="#添加供应商" aria-label="Permalink to &quot;添加供应商&quot;">​</a></h3><ol><li><p>打开 CC Switch，在 Claude Code 配置中点击 <code>添加供应商</code>。</p></li><li><p>预设供应商选择 <code>Suirenai</code>，并按照下方内容填写：</p><ul><li><strong>官网链接</strong> ：<code>https://api.suirenai.com</code></li><li><strong>API Key</strong> ：填写刚才创建的 <code>codex</code> 分组 API Key</li><li><strong>请求地址</strong> ：<code>https://api.suirenai.com</code></li><li><strong>API 格式</strong> ：<code>OpenAI Responses API（需开启路由）</code></li><li><strong>主模型</strong> ：填写你希望映射到 Claude Code 主模型的 GPT 模型，例如 <code>gpt-5.5</code></li><li><strong>Haiku 默认模型</strong> ：填写较轻量的 GPT 模型，例如 <code>gpt-5.4-mini</code></li><li><strong>Sonnet 默认模型</strong> ：填写你希望映射到 Sonnet 的 GPT 模型，例如 <code>gpt-5.5</code></li><li><strong>Opus 默认模型</strong> ：填写你希望映射到 Opus 的 GPT 模型，例如 <code>gpt-5.5</code></li></ul></li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ChatGPTClaudeCode/02.webp" alt=""></p><p>模型填写说明</p><p>上方模型名称仅用于示例，请以你创建令牌时 <code>codex</code> 分组实际可用的模型名称为准。如果模型名称填写错误，Claude Code 中可能会出现模型不存在、请求失败或日志映射异常。</p><h3 id="开启本地路由" tabindex="-1">开启本地路由 <a class="header-anchor" href="#开启本地路由" aria-label="Permalink to &quot;开启本地路由&quot;">​</a></h3><ol><li>回到 CC Switch 主界面，点击左上角的设置按钮。</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ChatGPTClaudeCode/03.webp" alt=""></p><ol start="2"><li>在设置页切换到 <code>路由</code>，展开 <code>本地路由</code>。</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ChatGPTClaudeCode/04.webp" alt=""></p><ol start="3"><li>打开 <code>路由总开关</code>，并在 <code>路由启用</code> 中只开启 <code>Claude</code>。不需要为 Codex 或 Gemini 开启该路由。</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ChatGPTClaudeCode/05.webp" alt=""></p><ol start="4"><li>回到 CC Switch 主界面，顶部应出现本地路由开关；确认开关处于开启状态，并选中刚才添加的 <code>Suirenai-codex</code> 供应商。</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ChatGPTClaudeCode/06.webp" alt=""></p><p>如果后续需要停止该方案，可以关闭主界面顶部的本地路由开关，或回到设置页关闭 <code>路由总开关</code>。</p><h2 id="验证配置" tabindex="-1">验证配置 <a class="header-anchor" href="#验证配置" aria-label="Permalink to &quot;验证配置&quot;">​</a></h2><ol><li>检查 Claude Code 的 <code>settings.json</code>。开启本地路由后，<code>ANTHROPIC_BASE_URL</code> 应该变为本地代理地址，<code>ANTHROPIC_AUTH_TOKEN</code> 通常会由 CC Switch 接管。</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ChatGPTClaudeCode/07.webp" alt=""></p><ol start="2"><li>重新打开终端，运行 <code>claude</code> 启动 Claude Code，并发送一条测试消息。能够正常回复，说明 Claude Code 已经可以通过本地路由发起请求。</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ChatGPTClaudeCode/08.webp" alt=""></p><ol start="3"><li>回到 CC Switch 的 <code>使用统计</code>，查看 <code>请求日志</code>。日志中可能仍显示 Claude Code 侧的映射模型，例如 <code>claude-opus-4-7</code>，这是本地路由映射后的请求表现。</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ChatGPTClaudeCode/09.webp" alt=""></p><ol start="4"><li>最后到 Suirenai 的消费日志中确认实际调用情况。如果配置正确，消费日志中应显示 <code>codex</code> 分组，并记录实际扣费的 GPT 模型，例如 <code>gpt-5.5</code>。</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ChatGPTClaudeCode/10.webp" alt=""></p><h2 id="使用风险" tabindex="-1">使用风险 <a class="header-anchor" href="#使用风险" aria-label="Permalink to &quot;使用风险&quot;">​</a></h2><p>最后提醒</p><p>该方案属于非推荐玩法，可能因为 Claude Code、CC Switch、模型接口、缓存策略、MCP 或 Skills 行为变化而失效。</p><p>Suirenai 不推荐用户将 GPT 模型接入 Claude Code，也不对该方案的稳定性、兼容性、输出效果、额度消耗或任何衍生问题承担责任。你可以用于测试、研究和理解路由逻辑，但不建议把它作为日常稳定工作流使用。</p>',43)])])}const u=a(t,[["render",i]]);export{h as __pageData,u as default};
